import sys, os, json, base64
sys.path.insert(0, ".")

calendar = json.loads(base64.b64decode("").decode())

from db.connection import get_conn
with get_conn() as conn:
    with conn.cursor() as cur:
        cur.execute(
            "INSERT INTO decisions (decided_by, decision_type, input_context, reasoning, output) "
            "VALUES (%s, %s, %s, %s, %s)",
            ("claude_direct", "calendar_plan",
             "May 2026 calendar — manual generation, full month coverage",
             "Generated directly from real RPR data. Covers May 14-31, all 7 days including weekends. Memorial Day themed campaign on May 25.",
             json.dumps(calendar))
        )
    conn.commit()
    print("Calendar inserted into decisions table")

# Publish to Shopify
try:
    from pacing.calendar import _generate_html_report, _publish_calendar_page
    from datetime import date
    month_start = date(2026, 5, 1)
    html = _generate_html_report(month_start, calendar)
    url = _publish_calendar_page(month_start, html)
    print("Published to Shopify:", url)
except Exception as e:
    print("Shopify publish failed (do manually):", e)

print()
print("Done. Calendar covers May 14-31:")
print(f"  {len(calendar['slots'])} total slots")
print(f"  Includes weekends + Memorial Day")
print(f"  Based on real Klaviyo RPR data")
